const checkpoints = [];

const search = JSON.parse(localStorage.getItem('task1_searchParams') || 'null');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

// CP1 (0.30): Used search with correct time-management filters (English, maxPrice<=15, minRating>=4.0, sorted by price_asc, query mentions "time management")
let searchOk = false;
if (search) {
  const q = (search.query || '').toLowerCase();
  const filters = search.filters || {};
  const hasTM = q.includes('time management');
  const langOk = filters.language === 'english';
  const maxPriceOk = typeof filters.maxPrice === 'number' && filters.maxPrice <= 15;
  const minRatingOk = typeof filters.minRating === 'number' && filters.minRating >= 4.0;
  const sortOk = search.sortBy === 'price_asc';
  searchOk = hasTM && langOk && maxPriceOk && minRatingOk && sortOk;
}
checkpoints.push({ passed: searchOk, weight: 0.30 });

// Helper: latest cart by updatedAt
let latestCart = null;
if (Array.isArray(carts) && carts.length) {
  latestCart = carts.slice().sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0))[0];
}

// CP2 (0.70): Latest cart has exactly one item, and it is the cheapest qualifying English time-management ebook under $15 with rating>=4.0
let cartOk = false;
if (latestCart) {
  const ciIds = Array.isArray(latestCart.items) ? latestCart.items : [];
  const cartItems = cartItemsAll.filter(ci => ci.cartId === latestCart.id && ciIds.includes(ci.id));
  if (cartItems.length === 1 && Number(cartItems[0].quantity || 0) === 1) {
    const pid = cartItems[0].productId;
    const qualifying = products.filter(p => {
      if (!p) return false;
      const hasTMKeyword = Array.isArray(p.keywords) && p.keywords.some(k => typeof k === 'string' && k.toLowerCase().includes('time management'));
      return p.format === 'ebook'
        && p.language === 'english'
        && typeof p.price === 'number' && p.price < 15
        && typeof p.averageRating === 'number' && p.averageRating >= 4.0
        && hasTMKeyword;
    });
    if (qualifying.length) {
      const minPrice = Math.min(...qualifying.map(p => p.price));
      const cheapestIds = qualifying.filter(p => p.price === minPrice).map(p => p.id);
      cartOk = cheapestIds.includes(pid);
    }
  }
}
checkpoints.push({ passed: cartOk, weight: 0.70 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

