// CP1 (0.30): Used search with correct Python programming filters (query mentions python + programming, maxPrice<=30, English, rating_desc)
let searchOk = false;
if (search) {
  const q = (search.query || '').toLowerCase();
  const filters = search.filters || {};
  const hasPython = q.includes('python');
  const hasProgramming = q.includes('programming');
  const maxPriceOk = typeof filters.maxPrice === 'number' && filters.maxPrice <= 30;
  const langOk = !filters.language || filters.language === 'english';
  const sortOk = search.sortBy === 'rating_desc';
  searchOk = hasPython && hasProgramming && maxPriceOk && langOk && sortOk;
}
checkpoints.push({ passed: searchOk, weight: 0.30 });

// Helper: latest cart
let latestCart = null;
if (Array.isArray(carts) && carts.length) {
  latestCart = carts.slice().sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0))[0];
}

// CP2 (0.70): Latest cart has exactly one item, which is the longer of the top two highest-rated qualifying Python-programming ebooks under $30
let cartOk = false;
if (latestCart) {
  const ciIds = Array.isArray(latestCart.items) ? latestCart.items : [];
  const cartItems = cartItemsAll.filter(ci => ci.cartId === latestCart.id && ciIds.includes(ci.id));
  if (cartItems.length === 1 && Number(cartItems[0].quantity || 0) === 1) {
    const pid = cartItems[0].productId;
    const candidates = products.filter(p => {
      if (!p) return false;
      const hasKeyword = Array.isArray(p.keywords) && p.keywords.some(k => typeof k === 'string' && k.toLowerCase() === 'python programming');
      return p.format === 'ebook'
        && p.language === 'english'
        && typeof p.price === 'number' && p.price <= 30
        && hasKeyword;
    });
    if (candidates.length >= 2) {
      const sorted = candidates.slice().sort((a, b) => {
        const diff = (b.averageRating || 0) - (a.averageRating || 0);
        if (diff !== 0) return diff;
        return (b.ratingCount || 0) - (a.ratingCount || 0);
      });
      const top2 = sorted.slice(0, 2);
      const maxPage = Math.max(...top2.map(p => p.pageCount || 0));
      const preferredIds = top2.filter(p => (p.pageCount || 0) === maxPage).map(p => p.id);
      cartOk = preferredIds.includes(pid);
    }
  }
}
checkpoints.push({ passed: cartOk, weight: 0.70 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

