const search = JSON.parse(localStorage.getItem('task5_searchParams') || 'null');
const checkoutStarted = JSON.parse(localStorage.getItem('task5_checkoutStarted') || 'false');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
