// CP1 (0.25): Used search with correct Fantasy upcoming-preorder filters (upcoming, onlyPreorderAvailable, releaseDateFrom>=2025-01-01, maxPrice<=25, release_date_asc)
let searchOk = false;
if (search) {
  const filters = search.filters || {};
  const categoryOk = search.categoryCode === 'fantasy';
  const availabilityOk = filters.availability === 'upcoming';
  const preorderOk = filters.onlyPreorderAvailable === true;
  const maxPriceOk = typeof filters.maxPrice === 'number' && filters.maxPrice <= 25;
  const fromStr = filters.releaseDateFrom;
  let fromOk = false;
  if (fromStr) {
    const fromTime = new Date(fromStr).getTime();
    const minTime = new Date('2025-01-01T00:00:00Z').getTime();
    fromOk = !isNaN(fromTime) && fromTime >= minTime;
  }
  const sortOk = search.sortBy === 'release_date_asc';
  searchOk = categoryOk && availabilityOk && preorderOk && maxPriceOk && fromOk && sortOk;
}
checkpoints.push({ passed: searchOk, weight: 0.25 });

// Helper: find earliest qualifying upcoming fantasy preorder under $25 after 2025-01-01
const qualifying = products.filter(p => {
  if (!p) return false;
  const relTime = p.releaseDate ? new Date(p.releaseDate).getTime() : NaN;
  const minTime = new Date('2025-01-01T00:00:00Z').getTime();
  return p.categoryId === 'fantasy'
    && p.format === 'ebook'
    && p.availabilityStatus === 'upcoming'
    && !!p.isPreorderAvailable
    && typeof p.price === 'number' && p.price < 25
    && !isNaN(relTime) && relTime >= minTime;
});
let targetId = null;
if (qualifying.length) {
  const sortedQ = qualifying.slice().sort((a, b) => new Date(a.releaseDate || 0) - new Date(b.releaseDate || 0));
  targetId = sortedQ[0].id;
}

// Helper: latest cart
let latestCart = null;
if (Array.isArray(carts) && carts.length) {
  latestCart = carts.slice().sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0))[0];
}

// CP2 (0.35): Latest cart has exactly one item which is that earliest qualifying fantasy preorder, marked as preorder
let cartOk = false;
if (latestCart && targetId) {
  const ciIds = Array.isArray(latestCart.items) ? latestCart.items : [];
  const cartItems = cartItemsAll.filter(ci => ci.cartId === latestCart.id && ciIds.includes(ci.id));
  if (cartItems.length === 1 && Number(cartItems[0].quantity || 0) === 1) {
    const ci = cartItems[0];
    cartOk = ci.productId === targetId && !!ci.isPreorder;
  }
}
checkpoints.push({ passed: cartOk, weight: 0.35 });

// CP3 (0.40): User proceeded to checkout while having that correct single preorder in cart
const checkoutOk = checkoutStarted === true && cartOk;
checkpoints.push({ passed: checkoutOk, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

