const promoCodes = JSON.parse(localStorage.getItem('promo_codes') || '[]');

// CP1 (0.25): Used search with correct Romance filters (price>15, rating>=4.0, rating_desc)
let searchOk = false;
if (search) {
  const filters = search.filters || {};
  const categoryOk = search.categoryCode === 'romance';
  const minPriceOk = typeof filters.minPrice === 'number' && filters.minPrice > 15;
  const minRatingOk = typeof filters.minRating === 'number' && filters.minRating >= 4.0;
  const sortOk = search.sortBy === 'rating_desc';
  searchOk = categoryOk && minPriceOk && minRatingOk && sortOk;
