checkpoints.push({ passed: searchOk, weight: 0.25 });

// Helper: latest cart
let latestCart = null;
if (Array.isArray(carts) && carts.length) {
  latestCart = carts.slice().sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0))[0];
}

// Helper: qualifying romance products and their top two by rating
const qualifying = products.filter(p => {
  if (!p) return false;
  return p.categoryId === 'romance'
    && p.format === 'ebook'
    && typeof p.price === 'number' && p.price > 15
    && typeof p.averageRating === 'number' && p.averageRating >= 4.0;
});
let top2Ids = [];
if (qualifying.length >= 2) {
  const sortedQ = qualifying.slice().sort((a, b) => {
    const diff = (b.averageRating || 0) - (a.averageRating || 0);
    if (diff !== 0) return diff;
    return (b.ratingCount || 0) - (a.ratingCount || 0);
  });
  top2Ids = sortedQ.slice(0, 2).map(p => p.id);
}

// CP2 (0.35): Latest cart has exactly two items which are the top two qualifying romance ebooks and their combined base price > $30
let itemsOk = false;
let cartSubtotalFromProducts = 0;
if (latestCart && top2Ids.length === 2) {
  const ciIds = Array.isArray(latestCart.items) ? latestCart.items : [];
  const cartItems = cartItemsAll.filter(ci => ci.cartId === latestCart.id && ciIds.includes(ci.id));
  if (cartItems.length === 2) {
    const cartProductIds = cartItems.map(ci => ci.productId);
    const allTop2Present = cartProductIds.every(id => top2Ids.includes(id));
    if (allTop2Present) {
      cartSubtotalFromProducts = cartItems.reduce((sum, ci) => {
        const p = products.find(pr => pr.id === ci.productId);
        const price = p && typeof p.price === 'number' ? p.price : 0;
        const qty = Number(ci.quantity || 0) || 1;
        return sum + price * qty;
      }, 0);
      itemsOk = cartSubtotalFromProducts > 30;
    }
  }
}
checkpoints.push({ passed: itemsOk, weight: 0.35 });

// CP3 (0.40): READ10 promo code applied to that cart, valid for subtotal>=$30, giving a nonzero discount
let promoOk = false;
if (latestCart && itemsOk) {
  const read10 = promoCodes.find(p => (p.code || '').toUpperCase() === 'READ10');
  const promoId = read10 ? read10.id : null;
  const promoApplied = promoId && Array.isArray(latestCart.promoCodeIds) && latestCart.promoCodeIds.includes(promoId);
  const subtotal = Number(latestCart.subtotal || 0);
  const discountTotal = Number(latestCart.discountTotal || 0);
  const minTotalOk = read10 && typeof read10.minOrderTotal === 'number' ? subtotal >= read10.minOrderTotal : subtotal >= 30;
  promoOk = promoApplied && minTotalOk && discountTotal > 0;
}
checkpoints.push({ passed: promoOk, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

