const checkpoints = [];

const authorSearch = JSON.parse(localStorage.getItem('task8_authorSearchParams') || 'null');
const authorBrowse = JSON.parse(localStorage.getItem('task8_authorBrowseParams') || 'null');
const authors = JSON.parse(localStorage.getItem('authors') || '[]');
const products = JSON.parse(localStorage.getItem('products') || '[]');
const carts = JSON.parse(localStorage.getItem('carts') || '[]');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');

const neil = authors.find(a => a.id === 'neil_gaiman' || (a.name || '').toLowerCase() === 'neil gaiman') || null;

// CP1 (0.30): Searched for Neil Gaiman and browsed that author's products with correct filters (maxPrice<=18, minRating>=4, English, rating_desc)
let searchOk = false;
if (authorSearch && authorBrowse && neil) {
  const q = (authorSearch.query || '').toLowerCase();
  const searchedNeil = q.includes('neil') && q.includes('gaiman');
  const authorIdOk = authorBrowse.authorId === neil.id;
  const filters = authorBrowse.filters || {};
  const maxPriceOk = typeof filters.maxPrice === 'number' && filters.maxPrice <= 18;
  const minRatingOk = typeof filters.minRating === 'number' ? filters.minRating >= 4.0 : true;
  const langOk = !filters.language || filters.language === 'english';
  const sortOk = !authorBrowse.sortBy || authorBrowse.sortBy === 'rating_desc';
  searchOk = searchedNeil && authorIdOk && maxPriceOk && minRatingOk && langOk && sortOk;
}
checkpoints.push({ passed: searchOk, weight: 0.30 });

// Helper: latest cart and its products
let latestCart = null;
let cartItems = [];
let cartProducts = [];
if (Array.isArray(carts) && carts.length) {
  latestCart = carts.slice().sort((a, b) => new Date(b.updatedAt || 0) - new Date(a.updatedAt || 0))[0];
}
if (latestCart) {
  const ciIds = Array.isArray(latestCart.items) ? latestCart.items : [];
  cartItems = cartItemsAll.filter(ci => ci.cartId === latestCart.id && ciIds.includes(ci.id));
  cartProducts = cartItems.map(ci => {
    const p = products.find(pr => pr.id === ci.productId);
    return p ? { cartItem: ci, product: p } : null;
  }).filter(x => !!x);
}

// CP2 (0.30): Cart contains at least one qualifying Neil Gaiman ebook (under $18, rating>=4.0)
let primaryProducts = [];
let primaryOk = false;
if (neil && cartProducts.length) {
  primaryProducts = cartProducts.filter(x => {
    const p = x.product;
    return p.authorId === neil.id
      && typeof p.price === 'number' && p.price < 18
      && typeof p.averageRating === 'number' && p.averageRating >= 4.0;
  });
  primaryOk = primaryProducts.length >= 1;
}
checkpoints.push({ passed: primaryOk, weight: 0.30 });

// CP3 (0.40): For at least one such primary, cart has exactly three items and at least two are qualifying recommended ebooks (from its recommendedProductIds, under $18, rating>=4.0)
let recommendationsOk = false;
if (primaryProducts.length && latestCart && cartProducts.length === 3) {
  for (const entry of primaryProducts) {
    const primary = entry.product;
    const recIds = Array.isArray(primary.recommendedProductIds) ? primary.recommendedProductIds : [];
    const recInCart = cartProducts.filter(x => {
      const p = x.product;
      if (p.id === primary.id) return false;
      const inRecs = recIds.includes(p.id);
      const priceOk = typeof p.price === 'number' && p.price < 18;
      const ratingOk = typeof p.averageRating === 'number' && p.averageRating >= 4.0;
      return inRecs && priceOk && ratingOk;
    });
    if (recInCart.length >= 2) {
      recommendationsOk = true;
      break;
    }
  }
}
checkpoints.push({ passed: recommendationsOk, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
